    expect(effect.commitGraphicalScale).toBeDefined();
    expect(effect.commitGraphicalScale?.referenceMm).toEqual({ xMm: 1000, yMm: 0 });
    expect(effect.commitGraphicalScale?.destinationMm).toEqual({ xMm: 2000, yMm: 0 });
  });
});

