  let peerIdStored = '';

  try {
    peerIdStored = sessionStorage.getItem('bim.peerId') ?? '';
  } catch {
    peerIdStored = '';
  }

  const peerSeed =
    peerIdStored ||
    (() => {
      const p = newPeerIdentity();

      try {
        sessionStorage.setItem('bim.peerId', p);
      } catch {
        /* noop */
      }

      return p;
    })();

  try {
    sessionStorage.setItem('bim.peerId', peerSeed);
  } catch {
    /* noop */

