1	import type { XY } from '@bim-ai/core';
2	
3	export interface ScaleElementCommand {
4	  type: 'scaleElement';
5	  elementId: string;
6	  originXMm: number;
7	  originYMm: number;
8	  factor: number;
9	}
10	
11	/**
12	 * Parses a user-typed scale factor string.
13	 * Valid: finite positive number not equal to 0. Returns null for invalid input.
14	 */
15	export function parseScaleFactor(value: string): number | null {
16	  const trimmed = value.trim();
17	  if (trimmed === '') return null;
18	  const num = Number(trimmed);
19	  if (!Number.isFinite(num)) return null;
20	  if (num <= 0) return null;
21	  return num;
22	}
23	
24	/**
25	 * Computes a scale factor from two-click reference distance.
26	 * refDistanceMm is the distance between clicks in the "from" position,
27	 * newDistanceMm is the "to" distance. Returns null if either is <= 0.
28	 */
29	export function scaleFactorFromDistances(
30	  refDistanceMm: number,
31	  newDistanceMm: number,
32	): number | null {
33	  if (refDistanceMm <= 0 || newDistanceMm <= 0) return null;
34	  return newDistanceMm / refDistanceMm;
35	}
36	
37	/**
38	 * Scales an XY point relative to an origin by a given factor.
39	 */
40	export function scalePoint(point: XY, origin: XY, factor: number): XY {
41	  return {
42	    xMm: origin.xMm + (point.xMm - origin.xMm) * factor,
43	    yMm: origin.yMm + (point.yMm - origin.yMm) * factor,
44	  };
45	}
46	
47	/**
48	 * Scales wall endpoints relative to an origin.
49	 * Returns new start/end coordinates.
50	 */
51	export function scaleWallEndpoints(
52	  start: XY,
53	  end: XY,
54	  origin: XY,
55	  factor: number,
56	): { start: XY; end: XY } {
57	  return {
58	    start: scalePoint(start, origin, factor),
59	    end: scalePoint(end, origin, factor),
60	  };
61	}
62	
63	/**
64	 * Scales a family instance insertion point relative to an origin.
65	 * Returns the new insertion point and the scaled size (width * factor, height * factor).
66	 */
67	export function scaleFamilyInstance(
68	  insertionPoint: XY,
69	  widthMm: number,
70	  heightMm: number,
71	  origin: XY,
72	  factor: number,
73	): { insertionPoint: XY; widthMm: number; heightMm: number } {
74	  return {
75	    insertionPoint: scalePoint(insertionPoint, origin, factor),
76	    widthMm: widthMm * factor,
77	    heightMm: heightMm * factor,
78	  };
79	}
80	
81	/**
82	 * Builds a ScaleElementCommand for the given element and factor.
83	 */
84	export function buildScaleCommand(
85	  elementId: string,
86	  origin: XY,
87	  factor: number,
88	): ScaleElementCommand {
89	  return {
90	    type: 'scaleElement',
91	    elementId,
92	    originXMm: origin.xMm,
93	    originYMm: origin.yMm,
94	    factor,
95	  };
96	}
97	
98	/**
99	 * Distance between two points in mm.
100	 */
101	export function distanceMm(a: XY, b: XY): number {
102	  const dx = b.xMm - a.xMm;
103	  const dy = b.yMm - a.yMm;
104	  return Math.sqrt(dx * dx + dy * dy);
105	}
